import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin, getChatChannelMeta } from "openclaw/plugin-sdk/core";
import type { PulseBoardAccount } from "./types.js";

/** Resolved account shape used internally by the PulseBoard channel plugin. */
interface ResolvedPulseBoardAccount extends PulseBoardAccount {
  accountId: string;
  /** True when boardUrl and apiToken are both non-empty. */
  configured: boolean;
}

/** Resolve a PulseBoardAccount from raw config, returning stub defaults when absent. */
function resolvePulseBoardAccount(
  cfg: unknown,
  accountId?: string | null,
): ResolvedPulseBoardAccount {
  const aid = accountId?.trim() || "default";
  const channels = (cfg as Record<string, unknown> | undefined)?.channels as
    | Record<string, unknown>
    | undefined;
  const pbCfg = channels?.pulseboard as Record<string, unknown> | undefined;
  const accounts = pbCfg?.accounts as Record<string, Record<string, unknown>> | undefined;
  const raw = accounts?.[aid] ?? pbCfg ?? {};

  const boardUrl = String(raw.boardUrl ?? "").trim();
  const apiToken = String(raw.apiToken ?? "").trim();
  const username = String(raw.username ?? "").trim();

  return {
    accountId: aid,
    boardUrl,
    apiToken,
    username,
    configured: Boolean(boardUrl && apiToken),
  };
}

/** List configured PulseBoard account IDs from config. */
function listPulseBoardAccountIds(cfg: unknown): string[] {
  const channels = (cfg as Record<string, unknown> | undefined)?.channels as
    | Record<string, unknown>
    | undefined;
  const pbCfg = channels?.pulseboard as Record<string, unknown> | undefined;
  const accounts = pbCfg?.accounts as Record<string, unknown> | undefined;
  if (accounts) {
    return Object.keys(accounts);
  }
  // Fall back to implicit "default" account when top-level config is present.
  return pbCfg ? ["default"] : [];
}

// Resolve channel meta from the plugin registry.
// Uses a type cast since "pulseboard" is a new channel being introduced
// through this plugin and is not yet in the core channel ID registry.
const pulseBoardMeta = getChatChannelMeta(
  "pulseboard" as Parameters<typeof getChatChannelMeta>[0],
);

export const pulseBoardPlugin = createChatChannelPlugin<ResolvedPulseBoardAccount>({
  base: {
    id: "pulseboard",
    meta: {
      ...pulseBoardMeta,
      label: "PulseBoard",
      docsPath: "/channels/pulseboard",
      blurb: "Connect to PulseBoard bulletin messaging boards and direct messages.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: (cfg) => listPulseBoardAccountIds(cfg),
      resolveAccount: (cfg, accountId) => resolvePulseBoardAccount(cfg, accountId),
      defaultAccountId: () => "default",
      isConfigured: (account) => account.configured,
      describeAccount: (account) => ({
        accountId: account.accountId,
        configured: account.configured,
        extra: {
          boardUrl: account.boardUrl,
          username: account.username,
        },
      }),
    },
    setup: {
      // Apply PulseBoard account config fields into the main config object.
      applyAccountConfig: ({ cfg, accountId, input }) => {
        const aid = accountId ?? "default";
        const existing = cfg as Record<string, unknown>;
        const channels = ((existing.channels ?? {}) as Record<string, unknown>);
        const pbCfg = ((channels.pulseboard ?? {}) as Record<string, unknown>);
        const accounts = ((pbCfg.accounts ?? {}) as Record<string, unknown>);
        return {
          ...existing,
          channels: {
            ...channels,
            pulseboard: {
              ...pbCfg,
              accounts: {
                ...accounts,
                [aid]: {
                  boardUrl: (input as Record<string, unknown>).boardUrl ?? "",
                  apiToken: (input as Record<string, unknown>).apiToken ?? "",
                  username: (input as Record<string, unknown>).username ?? "",
                },
              },
            },
          },
        } as typeof cfg;
      },
    },
    gateway: {
      // Stub: log connection attempt; a real implementation would establish a
      // WebSocket or polling connection to the PulseBoard API.
      startAccount: async (ctx) => {
        const account = ctx.account;
        ctx.log?.info?.(
          `[pulseboard] connecting to PulseBoard for account "${account.accountId}" (${account.boardUrl || "no url configured"})`,
        );
        if (!account.configured) {
          throw new Error(
            `PulseBoard is not configured for account "${account.accountId}" — set boardUrl and apiToken under channels.pulseboard.`,
          );
        }
        ctx.log?.info?.(`[pulseboard] account "${account.accountId}" started`);
      },
    },
    messaging: {
      // Normalize board/user targets by trimming surrounding whitespace.
      normalizeTarget: (raw) => raw.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    // Stub: a real implementation would POST to the PulseBoard boards or DM API.
    sendText: async ({ to, accountId }) => {
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pulseboard-${Date.now()}`,
      });
    },
  },
});

